+  if (raw === "pi") {
+    return "pi";
+  }
+  if (raw === "codex" || raw === "codex-app-server" || raw === "app-server") {
+    return "codex";
+  }
+  if (raw === "auto") {
+    return "auto";
+  }
+  return raw;
+}

